        |      {
        |        "$type": "protocatalyst.expr.ProtoExpr.ColumnRef",
        |        "name": "name",
        |        "qualifier": null,
        |        "dataType": {"$type": "protocatalyst.types.ProtoType.StringType"},
        |        "nullable": true
        |      }
        |    ],
        |    "child": {
        |      "$type": "protocatalyst.plan.ProtoLogicalPlan.Filter",
        |      "condition": {
        |        "$type": "protocatalyst.expr.ProtoExpr.Gt",
        |        "left": {
        |          "$type": "protocatalyst.expr.ProtoExpr.ColumnRef",
        |          "name": "age",
        |          "qualifier": null,
        |          "dataType": {"$type": "protocatalyst.types.ProtoType.IntegerType"},
        |          "nullable": false
        |        },
        |        "right": {
        |          "$type": "protocatalyst.expr.ProtoExpr.Literal",
        |          "value": {"$type": "protocatalyst.expr.LiteralValue.IntValue", "value": 18}
        |        }
        |      },
        |      "child": {
        |        "$type": "protocatalyst.plan.ProtoLogicalPlan.RelationRef",
        |        "name": "users",
        |        "alias": null,
        |        "schema": {"tableName": "users", "fields": [], "fingerprint": 0}
        |      }
        |    }
        |  }
        |}""".stripMargin

    val result = ParityTester.testParity(sql, json)
    assert(result.protoPlan != null)
    assert(result.sparkPlan != null)
  }

